-- Basic SET option ON/OFF
ALTER DATABASE SCOPED CONFIGURATION
SET MAXDOP = 1;

ALTER DATABASE SCOPED CONFIGURATION
SET LEGACY_CARDINALITY_ESTIMATION = ON;

ALTER DATABASE SCOPED CONFIGURATION
SET PARAMETER_SNIFFING = OFF;

-- SET option with PRIMARY value
ALTER DATABASE SCOPED CONFIGURATION
SET MAXDOP = PRIMARY;

-- FOR SECONDARY
ALTER DATABASE SCOPED CONFIGURATION
FOR SECONDARY
SET MAXDOP = 4;

ALTER DATABASE SCOPED CONFIGURATION
FOR SECONDARY
SET LEGACY_CARDINALITY_ESTIMATION = PRIMARY;

-- ELEVATE_ONLINE / ELEVATE_RESUMABLE with special values
ALTER DATABASE SCOPED CONFIGURATION
SET ELEVATE_ONLINE = OFF;

ALTER DATABASE SCOPED CONFIGURATION
SET ELEVATE_ONLINE = WHEN_SUPPORTED;

ALTER DATABASE SCOPED CONFIGURATION
SET ELEVATE_RESUMABLE = FAIL_UNSUPPORTED;

-- CLEAR PROCEDURE_CACHE
ALTER DATABASE SCOPED CONFIGURATION
CLEAR PROCEDURE_CACHE;

-- CLEAR PROCEDURE_CACHE with plan handle
ALTER DATABASE SCOPED CONFIGURATION
CLEAR PROCEDURE_CACHE 0x06000500F443610F003B7CD12C02;
